// Basic FPGA Verilog — LED blinker
// Target: Xilinx Basys3 (xc7a35t) or any FPGA
module led_blink #(
  parameter CLK_HZ  = 100_000_000, // 100MHz clock
  parameter BLINK_HZ = 1           // 1Hz blink rate
) (
  input  logic clk,
  input  logic rst_n,
  output logic led
);
  localparam HALF_PERIOD = CLK_HZ / (2 * BLINK_HZ);
  logic [$clog2(HALF_PERIOD)-1:0] counter;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      counter <= 0;
      led     <= 0;
    end else if (counter == HALF_PERIOD - 1) begin
      counter <= 0;
      led     <= ~led;  // toggle LED
    end else begin
      counter <= counter + 1;
    end
  end
endmodule
// $clog2: ceiling log2 — auto-sizes counter width
// localparam: constant computed at elaboration time

// FPGA Design Flow — step by step

// STEP 1: RTL (led_blink.v)
// → Write Verilog describing behavior

// STEP 2: SYNTHESIS
// Vivado command:
// synth_design -top led_blink -part xc7a35tcpg236-1
// Result: netlist of LUTs and FFs
// LUT usage: ~5 LUTs for counter
// FF usage:  ~26 FFs for 26-bit counter

// STEP 3: CONSTRAINTS (led_blink.xdc)
// # Clock constraint
// create_clock -period 10.000 [get_ports clk]
// # Pin assignments (Basys3 board)
// set_property PACKAGE_PIN W5 [get_ports clk]  ;# 100MHz
// set_property PACKAGE_PIN U16 [get_ports led] ;# LED0
// set_property IOSTANDARD LVCMOS33 [get_ports *]

// STEP 4-5: PLACE & ROUTE + TIMING
// impl_design
// report_timing_summary -file timing.rpt
// WNS must be > 0 for clean timing

// STEP 6: BITSTREAM
// write_bitstream -file led_blink.bit

// STEP 7: PROGRAM
// open_hw_manager
// program_device [get_hw_devices] -bitfile led_blink.bit

