// One-hot FSM — Traffic Light Controller
(* fsm_encoding = "one_hot" *)  // Vivado attribute
module traffic_fsm (
  input  logic clk, rst_n,
  input  logic timer_done,
  output logic red, yellow, green
);
  typedef enum logic [2:0] {
    RED    = 3'b001,
    GREEN  = 3'b010,
    YELLOW = 3'b100
  } state_t;

  state_t state, next_state;

  // Process 1: State register (sequential)
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) state <= RED;
    else        state <= next_state;
  end

  // Process 2: Next state + output (combinational)
  always_comb begin
    next_state = state; // default: stay
    {red, yellow, green} = 3'b000;
    case (state)
      RED:    begin red=1;    if (timer_done) next_state=GREEN;  end
      GREEN:  begin green=1;  if (timer_done) next_state=YELLOW; end
      YELLOW: begin yellow=1; if (timer_done) next_state=RED;    end
      default: next_state = RED; // safe state
    endcase
  end
endmodule

// UART RX FSM
module uart_rx #(
  parameter CLK_HZ  = 100_000_000,
  parameter BAUD    = 115_200
) (
  input  logic clk, rst_n,
  input  logic rx,
  output logic [7:0] data,
  output logic       done
);
  localparam CLKS_PER_BIT  = CLK_HZ / BAUD;        // 868
  localparam HALF_BIT      = CLKS_PER_BIT / 2;     // 434

  typedef enum logic [1:0] {
    IDLE=2'b00, START=2'b01,
    DATA=2'b10, STOP=2'b11
  } state_t;

  state_t        state;
  logic [9:0]    baud_cnt;   // counts clocks per bit
  logic [2:0]    bit_idx;    // 0..7 data bits
  logic [7:0]    rx_shift;   // shift register

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      state<=IDLE; done<=0; data<=0;
    end else begin
      done <= 0; // default
      case (state)
        IDLE:  if (!rx) begin  // start bit detected
                 baud_cnt<=0; state<=START;
               end
        START: if (baud_cnt==HALF_BIT-1) begin  // sample middle
                 baud_cnt<=0; bit_idx<=0; state<=DATA;
               end else baud_cnt<=baud_cnt+1;
        DATA:  if (baud_cnt==CLKS_PER_BIT-1) begin
                 baud_cnt<=0;
                 rx_shift<={rx,rx_shift[7:1]};  // LSB first
                 if (bit_idx==7) state<=STOP;
                 else bit_idx<=bit_idx+1;
               end else baud_cnt<=baud_cnt+1;
        STOP:  if (baud_cnt==CLKS_PER_BIT-1) begin
                 data<=rx_shift; done<=1; state<=IDLE;
               end else baud_cnt<=baud_cnt+1;
      endcase
    end
  end
endmodule

