// Lab 2: Vending Machine FSM
module vending_machine (
  input  logic clk, rst_n,
  input  logic coin_10, coin_25,
  output logic dispense, ret_10,
  output logic [5:0] credit
);
  typedef enum logic [2:0] {
    S0  = 3'd0,   // 0 cents
    S10 = 3'd1,   // 10 cents
    S20 = 3'd2,   // 20 cents
    S25 = 3'd3,   // 25 cents
    S30 = 3'd4,   // 30 cents
    S35 = 3'd5    // 35+ cents → dispense
  } state_t;

  state_t state, next_state;
  logic   next_dispense, next_ret10;
  logic [5:0] next_credit;

  // State register
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      state<=S0; dispense<=0; ret_10<=0; credit<=0;
    end else begin
      state    <= next_state;
      dispense <= next_dispense;
      ret_10   <= next_ret10;
      credit   <= next_credit;
    end
  end

  // Next state logic
  always_comb begin
    next_state    = state;
    next_dispense = 0;
    next_ret10    = 0;
    next_credit   = credit;
    case (state)
      S0:  begin next_credit=0;
             if (coin_10) begin next_state=S10; next_credit=10; end
             if (coin_25) begin next_state=S25; next_credit=25; end
           end
      S10: begin next_credit=10;
             if (coin_10) begin next_state=S20; next_credit=20; end
             if (coin_25) begin next_state=S35; next_credit=35; end
           end
      S20: begin next_credit=20;
             if (coin_10) begin next_state=S30; next_credit=30; end
             if (coin_25) begin next_state=S35; next_credit=45;
                               next_ret10=1; end // 45-35=10 change
           end
      S25: begin next_credit=25;
             if (coin_10) begin next_state=S35; next_credit=35; end
             if (coin_25) begin next_state=S35; next_credit=50;
                               next_ret10=1; end
           end
      S30: begin next_credit=30;
             if (coin_10) begin next_state=S35; next_credit=40;
                               next_ret10=1; end
             if (coin_25) begin next_state=S35; next_credit=55;
                               next_ret10=1; end
           end
      S35: begin // Dispense and return to S0
             next_dispense=1; next_state=S0; next_credit=0;
           end
      default: next_state=S0;
    endcase
  end
endmodule

module tb_vending;
  logic clk=0, rst_n;
  logic coin_10, coin_25, dispense, ret_10;
  logic [5:0] credit;

  vending_machine dut(.*);
  always #5 clk = ~clk;

  task insert(input logic c10, c25);
    coin_10=c10; coin_25=c25;
    @(posedge clk); #1;
    coin_10=0; coin_25=0;
  endtask

  initial begin
    rst_n=0; coin_10=0; coin_25=0;
    @(posedge clk); rst_n=1;

    // Test 1: 25 + 10 = 35 → dispense
    insert(0,1); // 25 cents
    insert(1,0); // 10 cents
    @(posedge clk); #1;
    assert(dispense==1) else $error("Test1: no dispense");
    $display("Test1 PASSED: 25+10 dispenses");

    // Test 2: 10+10+10+10 = 40 → dispense + ret_10
    repeat(4) insert(1,0);
    @(posedge clk); #1;
    assert(dispense==1) else $error("Test2: no dispense");
    $display("Test2 PASSED: 4×10 dispenses");
    $finish;
  end
endmodule

