// FIFO operation trace (8-deep FIFO)
// Cycle  wr_en  rd_en  wdata  rdata  count  empty  full
//  1       1     0      AA     --     1      0      0
//  2       1     0      BB     --     2      0      0
//  3       1     0      CC     --     3      0      0
//  4       0     1      --     AA     2      0      0   ← 1-cycle latency
//  5       0     1      --     BB     1      0      0
//  6       0     1      --     CC     0      1      0   ← empty!
//  7       0     1      --     XX     0      1      0   ← INVALID READ!

// Key rules:
// NEVER write when full=1   → data lost
// NEVER read when empty=1   → garbage data
// ALWAYS check flags before R/W

// FIFO instantiation (Xilinx FIFO Generator IP)
fifo_generator_v13_2 #(
  .FIFO_DEPTH(256),
  .DATA_WIDTH(8)
) fifo_inst (
  .clk(clk), .rst(!rst_n),
  .wr_en(wr_en), .din(wdata),
  .rd_en(rd_en), .dout(rdata),
  .full(full), .empty(empty),
  .data_count(count)
);

