module tb_bram;
  logic clk=0, we;
  logic [3:0] waddr, raddr;
  logic [7:0] wdata, rdata;

  bram_16x8 dut(.*);
  always #5 clk = ~clk;

  initial begin
    we=0; waddr=0; wdata=0; raddr=0;

    // Write phase: write 4 values
    @(posedge clk);
    we=1; waddr=0; wdata=8'hA0; @(posedge clk);
    we=1; waddr=1; wdata=8'hB1; @(posedge clk);
    we=1; waddr=2; wdata=8'hC2; @(posedge clk);
    we=1; waddr=3; wdata=8'hD3; @(posedge clk);
