    assert(rdata==8'hB1) else $error("addr1: got %h",rdata);

    raddr=2; @(posedge clk); #1;
    assert(rdata==8'hC2) else $error("addr2: got %h",rdata);

    raddr=3; @(posedge clk); #1;
    assert(rdata==8'hD3) else $error("addr3: got %h",rdata);

