// Pipelined 8×8 multiplier → infers DSP48
module mult_pipe (
  input  logic        clk,
  input  logic [7:0]  a, b,
  output logic [15:0] p
);
  // Pipeline registers — maps to DSP48 internal regs
  logic [7:0]  a_reg, b_reg;  // input registers
  logic [15:0] p_reg;          // output register

  always_ff @(posedge clk) begin
    a_reg <= a;          // stage 1
    b_reg <= b;
    p_reg <= a_reg * b_reg; // stage 2 (DSP48 multiply)
    p     <= p_reg;      // stage 3 (output reg)
  end
endmodule

// 4-tap FIR filter
// y[n] = h0*x[n] + h1*x[n-1] + h2*x[n-2] + h3*x[n-3]
module fir4 (
  input  logic        clk, rst_n,
  input  logic signed [7:0]  x,
  output logic signed [15:0] y
);
  // Coefficients (symmetric: h0=h3, h1=h2)
  logic signed [7:0] h [4] = '{8'd1, 8'd3, 8'd3, 8'd1};
  logic signed [7:0] delay [4]; // delay line
  logic signed [15:0] products [4];
  logic signed [17:0] acc;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      foreach (delay[i]) delay[i] <= 0;
      y <= 0;
    end else begin
      delay[0] <= x;
      delay[1] <= delay[0];
      delay[2] <= delay[1];
      delay[3] <= delay[2];
      // Multiply-accumulate (each → DSP48)
      acc = h[0]*delay[0] + h[1]*delay[1]
          + h[2]*delay[2] + h[3]*delay[3];
      y <= acc[15:0];
    end
  end
endmodule

// MAC unit pipeline trace
// Operation: dot product of 4-element vectors A and B
// A = [1, 2, 3, 4], B = [5, 6, 7, 8]
// Expected: 1×5 + 2×6 + 3×7 + 4×8 = 5+12+21+32 = 70

// Cycle  a_in  b_in  a_reg b_reg  mult   acc    valid
//  1      1     5     1    5      -      -      0    ← load A,B regs
//  2      2     6     2    6      5      5      0    ← mult ready
//  3      3     7     3    7      12     17     0    ← accumulate
//  4      4     8     4    8      21     38     0
//  5      0     0     0    0      32     70     1    ← result ready!
//
// Latency = 2 cycles (input reg + multiply)
// Total: 4 inputs + 2 latency = 6 cycles to valid result

// Key insight:
// DSP48 computes a_reg * b_reg → registered product
// Accumulator adds product each cycle
// After N inputs, assert valid to indicate result ready

// Pipelining increases latency but allows higher Fmax
// Without pipeline: multiply is critical path → ~200MHz
// With 3-stage pipe: each stage <2.5ns → >400MHz

