// Lab 4: Pipelined MAC Unit
module mac_unit (
  input  logic        clk, rst_n,
  input  logic        clear,
  input  logic        valid_in,
  input  logic signed [7:0]  a, b,
  output logic signed [23:0] acc_out,
  output logic               valid_out
);
  // Pipeline stage registers
  logic signed [7:0]  a_reg, b_reg;        // Stage 1
  logic signed [15:0] product;              // Stage 2
  logic               valid_s1, valid_s2;  // valid pipeline

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      a_reg<=0; b_reg<=0; product<=0;
      acc_out<=0; valid_s1<=0; valid_s2<=0; valid_out<=0;
    end else begin
      // Stage 1: register inputs
      a_reg    <= a;
      b_reg    <= b;
      valid_s1 <= valid_in;

      // Stage 2: multiply
      product  <= a_reg * b_reg;
      valid_s2 <= valid_s1;

      // Stage 3: accumulate
      if (clear)
        acc_out <= 0;
      else if (valid_s2)
        acc_out <= acc_out + product;
      valid_out <= valid_s2;
    end
  end
endmodule

module tb_mac;
  logic clk=0, rst_n, clear, valid_in, valid_out;
  logic signed [7:0]  a, b;
  logic signed [23:0] acc_out;

  mac_unit dut(.*);
  always #5 clk = ~clk;

  task feed(input signed [7:0] ta, tb, input logic v=1);
    a=ta; b=tb; valid_in=v;
    @(posedge clk); #1;
  endtask

  initial begin
    rst_n=0; clear=0; valid_in=0; a=0; b=0;
    @(posedge clk); rst_n=1;

    // Compute [1,2,3,4]·[5,6,7,8] = 70
    clear=1; @(posedge clk); #1; clear=0;

    feed(1, 5);   // 1×5=5
    feed(2, 6);   // 2×6=12
    feed(3, 7);   // 3×7=21
    feed(4, 8);   // 4×8=32
    feed(0, 0, 0); // flush pipeline
    feed(0, 0, 0);

    // Pipeline latency = 2 cycles
    // Result should be 70
    $display("acc_out = %0d (expected 70)", acc_out);
    assert(acc_out == 70)
      else $error("MAC FAIL: got %0d", acc_out);

    $display("MAC unit PASSED");
    $finish;
  end
endmodule

