// 2-FF Synchronizer
(* ASYNC_REG = "TRUE" *) // Vivado: place in same slice
module sync_2ff (
  input  logic clk_dst,  // destination clock
  input  logic rst_n,
  input  logic d_src,    // from source domain
  output logic q_dst     // to destination domain
);
  (* ASYNC_REG = "TRUE" *)
  logic sync1, sync2;

  always_ff @(posedge clk_dst or negedge rst_n) begin
    if (!rst_n) begin sync1<=0; sync2<=0; end
    else begin
      sync1 <= d_src;  // may be metastable!
      sync2 <= sync1;  // resolved (MTBF > 1 billion years)
    end
  end
  assign q_dst = sync2;
endmodule

// Gray code conversion
function automatic [3:0] bin_to_gray(input [3:0] bin);
  return bin ^ (bin >> 1);
endfunction

function automatic [3:0] gray_to_bin(input [3:0] gray);
  logic [3:0] bin;
  bin[3] = gray[3];
  bin[2] = gray[3] ^ gray[2];
  bin[1] = gray[3] ^ gray[2] ^ gray[1];
  bin[0] = gray[3] ^ gray[2] ^ gray[1] ^ gray[0];
  return bin;
endfunction

// Async FIFO pointer logic trace
// FIFO depth = 8 (3-bit pointer, MSB for wrap detection)

// Initial: wptr=0000, rptr=0000 → empty
// Write 1: wptr=0001 (gray=0001)
// Write 2: wptr=0010 (gray=0011)
// Write 3: wptr=0011 (gray=0010)

// EMPTY check (in read domain):
// empty = (rptr_gray == wptr_gray_sync)
// If rptr_gray==wptr_gray_sync → nothing written yet → EMPTY

// FULL check (in write domain):
// Pointers have MSB for wrap counting (1 extra bit)
// Full when wptr and rptr differ only in MSB (wrapped)
// full = (wptr_gray[N:N-1] == ~rptr_gray_sync[N:N-1])
//       && (wptr_gray[N-2:0] == rptr_gray_sync[N-2:0])

// KEY: Gray code ensures only 1 bit changes per count
// Safe to sample across clock domains — no bus tear possible
// Even if synchronizer samples mid-transition, it just sees
// the old or new value — never a glitch combination

// Example: binary 3 (0011) → gray 0010
// binary 4 (0100) → gray 0110
// Only bit[1] changes: 0010→0110 ✓

