// Lab 5: CDC Synchronizer

// 2-FF Synchronizer
module sync_2ff (
  input  logic clk_dst, rst_n,
  input  logic d_src,
  output logic q_dst
);
  (* ASYNC_REG = "TRUE" *)
  logic sync1, sync2;

  always_ff @(posedge clk_dst or negedge rst_n) begin
    if (!rst_n) begin sync1<=0; sync2<=0; end
    else begin
      sync1 <= d_src;
      sync2 <= sync1;
    end
  end
  assign q_dst = sync2;
endmodule

// Pulse Synchronizer
// Toggle in src domain → sync → edge detect in dst
module pulse_sync (
  input  logic clk_src, clk_dst, rst_n,
  input  logic pulse_src,
  output logic pulse_dst
);
  logic toggle_src;  // toggles on each pulse
  logic toggle_dst;  // synchronized toggle
  logic toggle_dst_d; // delayed toggle

  // Toggle FF in source domain
  always_ff @(posedge clk_src or negedge rst_n)
    if (!rst_n) toggle_src <= 0;
    else if (pulse_src) toggle_src <= ~toggle_src;

  // Synchronize toggle into destination domain
  sync_2ff sync (
    .clk_dst, .rst_n,
    .d_src(toggle_src),
    .q_dst(toggle_dst)
  );

  // Edge detect: pulse when toggle changes
  always_ff @(posedge clk_dst or negedge rst_n)
    if (!rst_n) toggle_dst_d <= 0;
    else        toggle_dst_d <= toggle_dst;

  assign pulse_dst = toggle_dst ^ toggle_dst_d;
endmodule

// Testbench
module tb_cdc;
  logic clk_src=0, clk_dst=0, rst_n;
  logic pulse_src, pulse_dst;
  int pulse_count = 0;

  pulse_sync dut(.clk_src,.clk_dst,.rst_n,.pulse_src,.pulse_dst);

  always #5  clk_src = ~clk_src;  // 100MHz
  always #3.5 clk_dst = ~clk_dst; // ~143MHz

  // Count received pulses
  always @(posedge clk_dst)
    if (pulse_dst) pulse_count++;

  initial begin
    rst_n=0; pulse_src=0;
    repeat(5) @(posedge clk_src); rst_n=1;

    // Send 3 pulses in src domain
    repeat(3) begin
      @(posedge clk_src);
      pulse_src=1; @(posedge clk_src); #1;
      pulse_src=0;
      repeat(5) @(posedge clk_src); // gap between pulses
    end

    // Wait for synchronization
    repeat(20) @(posedge clk_dst);

    assert(pulse_count==3)
      else $error("CDC FAIL: got %0d pulses, exp 3",pulse_count);
    $display("CDC PASSED: %0d pulses received", pulse_count);
    $finish;
  end
endmodule

