// AXI4-Lite Slave — register interface
module axi_lite_slave #(
  parameter ADDR_W = 8,
  parameter DATA_W = 32
) (
  input  logic                 clk, rst_n,
  // Write address channel
  input  logic [ADDR_W-1:0]   awaddr,
  input  logic                 awvalid,
  output logic                 awready,
  // Write data channel
  input  logic [DATA_W-1:0]   wdata,
  input  logic                 wvalid,
  output logic                 wready,
  // Write response channel
  output logic [1:0]           bresp,   // 00=OKAY
  output logic                 bvalid,
  input  logic                 bready,
  // Read address channel
  input  logic [ADDR_W-1:0]   araddr,
  input  logic                 arvalid,
  output logic                 arready,
  // Read data channel
  output logic [DATA_W-1:0]   rdata,
  output logic [1:0]           rresp,
  output logic                 rvalid,
  input  logic                 rready
);
  logic [DATA_W-1:0] regs [64]; // 64 registers
  // ... state machine handles W and R channels
  assign bresp = 2'b00; // OKAY
  assign rresp = 2'b00;
endmodule

// AXI4-Stream Pipeline (video processing example)
//
// Camera → [Input FIFO] → [Pixel Proc] → [Output FIFO] → HDMI
//
// Each stage: TVALID/TREADY handshake

// Simple AXI-Stream register slice (add 1 pipeline stage)
module axis_register_slice #(
  parameter DATA_W = 8
) (
  input  logic             clk, rst_n,
  // Input stream
  input  logic             s_tvalid,
  output logic             s_tready,
  input  logic [DATA_W-1:0] s_tdata,
  input  logic             s_tlast,
  // Output stream
  output logic             m_tvalid,
  input  logic             m_tready,
  output logic [DATA_W-1:0] m_tdata,
  output logic             m_tlast
);
  logic             buf_valid;
  logic [DATA_W-1:0] buf_data;
  logic             buf_last;

  // Accept input when output is ready or buffer empty
  assign s_tready = !buf_valid || m_tready;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      buf_valid <= 0;
    end else if (s_tvalid && s_tready) begin
      buf_valid <= 1;
      buf_data  <= s_tdata;
      buf_last  <= s_tlast;
    end else if (m_tready) begin
      buf_valid <= 0;
    end
  end

  assign m_tvalid = buf_valid;
  assign m_tdata  = buf_data;
  assign m_tlast  = buf_last;
endmodule

