// Lab 6: AXI4-Lite Slave
module axi_lite_regs (
  input  logic        clk, rst_n,
  input  logic [3:0]  awaddr, araddr,
  input  logic        awvalid, wvalid, arvalid, bready, rready,
  input  logic [31:0] wdata,
  input  logic [3:0]  hw_status,
  output logic        awready, wready, bvalid, arready, rvalid,
  output logic [31:0] rdata,
  output logic [1:0]  bresp, rresp,
  output logic [31:0] ctrl_reg, data_reg
);
  assign bresp = 2'b00; // OKAY
  assign rresp = 2'b00;

  // Write channel
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      ctrl_reg<=0; data_reg<=0;
      awready<=0; wready<=0; bvalid<=0;
    end else begin
      awready <= awvalid; // accept address
      wready  <= wvalid;  // accept data
      if (awvalid && wvalid) begin
        case (awaddr[3:2])  // word address
          2'd0: ctrl_reg <= wdata;
          2'd2: data_reg <= wdata;
          // 2'd1 and 2'd3 are read-only
        endcase
        bvalid <= 1;
      end else if (bvalid && bready)
        bvalid <= 0;
    end
  end

  // Read channel
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin arready<=0; rvalid<=0; rdata<=0; end
    else begin
      arready <= arvalid;
      if (arvalid) begin
        rvalid <= 1;
        case (araddr[3:2])
          2'd0: rdata <= ctrl_reg;
          2'd1: rdata <= {28'b0, hw_status};  // status
          2'd2: rdata <= data_reg;
          2'd3: rdata <= 32'hDEAD_C0DE;        // ID
        endcase
      end else if (rvalid && rready)
        rvalid <= 0;
    end
  end

  assign data_reg = data_reg; // expose to design
endmodule

module tb_axi_lite;
  logic clk=0, rst_n;
  logic [3:0]  awaddr, araddr;
  logic        awvalid, wvalid, arvalid, bready, rready;
  logic [31:0] wdata;
  logic [3:0]  hw_status=4'hA;
  logic        awready, wready, bvalid, arready, rvalid;
  logic [31:0] rdata, ctrl_reg, data_reg;
  logic [1:0]  bresp, rresp;

  axi_lite_regs dut(.*);
  always #5 clk = ~clk;

  task axi_write(input [3:0] addr, input [31:0] data);
    awaddr=addr; wdata=data;
    awvalid=1; wvalid=1; bready=1;
    @(posedge clk); #1;
    wait(awready && wready);
    @(posedge clk);
    awvalid=0; wvalid=0;
    wait(bvalid); @(posedge clk);
  endtask

  task axi_read(input [3:0] addr, output [31:0] data);
    araddr=addr; arvalid=1; rready=1;
    @(posedge clk); #1;
    wait(rvalid);
    data = rdata;
    arvalid=0;
    @(posedge clk);
  endtask

  initial begin
    rst_n=0; awvalid=0; wvalid=0; arvalid=0; bready=0; rready=0;
    repeat(2) @(posedge clk); rst_n=1;

    // Write 0xABCD to ctrl_reg (addr 0x00)
    axi_write(4'h0, 32'h0000_ABCD);
    assert(ctrl_reg==32'h0000_ABCD)
      else $error("Write FAIL: ctrl=%h",ctrl_reg);

    // Read back ctrl_reg
    logic [31:0] rd;
    axi_read(4'h0, rd);
    assert(rd==32'h0000_ABCD)
      else $error("Read FAIL: got %h",rd);

    // Read ID register
    axi_read(4'hC, rd);
    assert(rd==32'hDEAD_C0DE)
      else $error("ID FAIL: got %h",rd);

    $display("AXI4-Lite PASSED");
    $finish;
  end
endmodule

