// HLS FIR Filter in C++
#include "ap_int.h"
#include "hls_stream.h"

typedef ap_int<8>  data_t;
typedef ap_int<16> acc_t;

void fir_filter(
  hls::stream<data_t>& in_stream,
  hls::stream<acc_t>&  out_stream
) {
  #pragma HLS PIPELINE II=1  // accept 1 sample per cycle

  static data_t shift_reg[8] = {0};
  const data_t  coeff[8]     = {1,2,3,4,4,3,2,1};

  #pragma HLS ARRAY_PARTITION variable=shift_reg complete
  #pragma HLS ARRAY_PARTITION variable=coeff     complete

  data_t x = in_stream.read();

  // Shift register update
  for (int i=7; i>0; i--) {
    #pragma HLS UNROLL
    shift_reg[i] = shift_reg[i-1];
  }
  shift_reg[0] = x;

  // MAC (all in parallel after unroll)
  acc_t result = 0;
  for (int i=0; i<8; i++) {
    #pragma HLS UNROLL
    result += coeff[i] * shift_reg[i];
  }
  out_stream.write(result);
}

// HLS Schedule Analysis for FIR filter
// After: #pragma HLS PIPELINE II=1
//        #pragma HLS UNROLL on loops

// Cycle 1:
//   Read x from stream
//   Shift: shift_reg[7]=shift_reg[6], ...
//   Multiply: coeff[0]*shift_reg[0] → p0
//             coeff[1]*shift_reg[1] → p1  (parallel!)
//             ...all 8 multiplies in parallel

// Cycle 2:
//   Add: p0+p1+p2+p3+p4+p5+p6+p7 (adder tree)
//   Write result to output stream

// HLS Resource Estimate:
// DSP48:  8 (one per multiply)
// FF:     8×8 = 64 (shift register)
// LUT:    ~50 (adder tree, control)
// Latency: 2 cycles
// II:     1 (new sample accepted every cycle)

// Without pragmas:
// Loop not unrolled → II = 8 (one multiply per cycle)
// With pragmas:
// All 8 multiplies in parallel → II = 1
// 8x throughput improvement from one pragma!

// HLS C simulation:
// cosim_design -O -rtl verilog
// → runs C testbench against RTL to verify behavior

