// Lab 7: Pipelined Dot Product (HLS-style parallel implementation)
module dot_product #(parameter N=4) (
  input  logic        clk, rst_n,
  input  logic        valid_in,
  input  logic signed [7:0] a [N],
  input  logic signed [7:0] b [N],
  output logic signed [23:0] result,
  output logic               valid_out
);
  // Stage 1: N parallel multipliers
  logic signed [15:0] products [N];
  logic valid_s1;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      valid_s1 <= 0;
      foreach (products[i]) products[i] <= 0;
    end else begin
      valid_s1 <= valid_in;
      for (int i=0; i<N; i++)
        products[i] <= a[i] * b[i];  // all in parallel!
    end
  end

  // Stage 2: Adder tree (for N=4: add pairs)
  logic signed [16:0] sum01, sum23;
  logic valid_s2;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin valid_s2<=0; sum01<=0; sum23<=0; end
    else begin
      valid_s2 <= valid_s1;
      sum01    <= products[0] + products[1];
      sum23    <= products[2] + products[3];
    end
  end

  // Stage 3: Final sum
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin result<=0; valid_out<=0; end
    else begin
      valid_out <= valid_s2;
      result    <= sum01 + sum23;
    end
  end
endmodule

module tb_dot;
  logic clk=0, rst_n, valid_in, valid_out;
  logic signed [7:0]  a [4], b [4];
  logic signed [23:0] result;
  int result_count = 0;

  dot_product dut(.*);
  always #5 clk = ~clk;

  // Verify results as they come out
  always @(posedge clk) begin
    if (valid_out) begin
      assert(result==24'd70)
        else $error("FAIL: got %0d", result);
      result_count++;
      $display("Result %0d: %0d (correct!)", result_count, result);
    end
  end

  initial begin
    rst_n=0; valid_in=0;
    foreach(a[i]) begin a[i]=0; b[i]=0; end
    @(posedge clk); rst_n=1;

    // Send 3 dot products
    repeat(3) begin
      a[0]=1; a[1]=2; a[2]=3; a[3]=4;
      b[0]=5; b[1]=6; b[2]=7; b[3]=8;
      valid_in=1;
      @(posedge clk); #1;
    end
    valid_in=0;

    // Wait for pipeline to drain (3 cycles latency)
    repeat(6) @(posedge clk);

    assert(result_count==3)
      else $error("Expected 3 results, got %0d", result_count);
    $display("Dot product PASSED: %0d results", result_count);
    $finish;
  end
endmodule

