// BEFORE: Timing violation
// Path: adder → mux → output_reg
// Delay: 15ns > 10ns period → WNS = -5ns

module bad_timing (
  input  logic        clk,
  input  logic [31:0] a, b,
  input  logic [2:0]  sel,
  output logic [31:0] out
);
  logic [31:0] sum;
  assign sum = a + b;  // 8ns
  // Big mux on adder output: +7ns
  always_ff @(posedge clk)
    case (sel)            // Total: 15ns! VIOLATION!
      3'd0: out <= sum;
      3'd1: out <= a;
      // ...
    endcase
endmodule

// AFTER: Pipeline register breaks the path
module fixed_timing (
  input  logic        clk,
  input  logic [31:0] a, b,
  input  logic [2:0]  sel,
  output logic [31:0] out
);
  logic [31:0] sum_reg; // PIPELINE REGISTER
  logic [31:0] a_reg;
  logic [2:0]  sel_reg;

  // Stage 1: compute sum (8ns — MEETS 10ns)
  always_ff @(posedge clk) begin
    sum_reg <= a + b;    // 8ns ✓
    a_reg   <= a;
    sel_reg <= sel;
  end

  // Stage 2: mux (6ns — MEETS 10ns)
  always_ff @(posedge clk)
    case (sel_reg)       // 6ns ✓
      3'd0: out <= sum_reg;
      3'd1: out <= a_reg;
      // ...
    endcase
endmodule
// Extra latency: 1 cycle
// But throughput: still 1 result/cycle!

