// Lab 8: Fixed Pipeline
// Original (slow) version for reference
module slow_path (
  input  logic        clk,
  input  logic [7:0]  a, b,
  input  logic [2:0]  shift_amt,
  output logic [23:0] result
);
  logic [15:0] product;
  logic [22:0] shifted;
  assign product = a * b;
  assign shifted = {7'b0, product} << shift_amt;
  always_ff @(posedge clk)
    result <= shifted + result;
endmodule

// Pipelined fix
module fast_path (
  input  logic        clk, rst_n,
  input  logic        valid_in,
  input  logic [7:0]  a, b,
  input  logic [2:0]  shift_amt,
  output logic [23:0] result,
  output logic        valid_out
);
  // Stage 1: multiply
  logic [15:0] product_reg;
  logic [2:0]  shift_reg;
  logic        valid_s1;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin product_reg<=0; valid_s1<=0; end
    else begin
      product_reg <= a * b;      // pipeline register!
      shift_reg   <= shift_amt;
      valid_s1    <= valid_in;
    end
  end

  // Stage 2: shift + accumulate
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin result<=0; valid_out<=0; end
    else begin
      valid_out <= valid_s1;
      if (valid_s1)
        result <= result + ({8'b0, product_reg} << shift_reg);
    end
  end
endmodule

module tb_pipeline_fix;
  logic clk=0, rst_n, valid_in, valid_out;
  logic [7:0]  a, b;
  logic [2:0]  shift_amt;
  logic [23:0] result;

  fast_path dut(.*);
  always #5 clk = ~clk;

  initial begin
    rst_n=0; valid_in=0; a=0; b=0; shift_amt=0;
    @(posedge clk); rst_n=1;

    // Apply: a=4, b=5, shift=2 for 3 cycles
    // Each cycle: product=20, shifted=80
    // After 3 cycles: result = 0+80+80+80 = 240
    a=4; b=5; shift_amt=2; valid_in=1;
    repeat(3) @(posedge clk);
    valid_in=0;

    // Wait for pipeline drain
    repeat(4) @(posedge clk); #1;

    $display("Result = %0d (expected 240)", result);
    assert(result==240) else $error("FAIL: got %0d",result);

    $display("Pipeline fix PASSED");
    $finish;
  end
endmodule

