// Lab 9: Zynq Timer Peripheral
module zynq_timer (
  input  logic        clk, rst_n,
  input  logic [3:0]  awaddr, araddr,
  input  logic        awvalid, wvalid, arvalid, bready, rready,
  input  logic [31:0] wdata,
  output logic        awready, wready, bvalid, arready, rvalid,
  output logic [31:0] rdata,
  output logic [1:0]  bresp, rresp,
  output logic        irq
);
  // Registers
  logic [31:0] ctrl_reg;   // 0x0
  logic [31:0] load_reg;   // 0x4
  logic [31:0] count_reg;  // 0x8 (RO)
  logic [31:0] status_reg; // 0xC

  assign bresp = 2'b00;
  assign rresp = 2'b00;

  logic enable      = ctrl_reg[0];
  logic auto_reload = ctrl_reg[1];

  // AXI Write
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      ctrl_reg<=0; load_reg<=0; awready<=0; wready<=0; bvalid<=0;
    end else begin
      awready <= awvalid;
      wready  <= wvalid;
      if (awvalid && wvalid) begin
        case (awaddr[3:2])
          2'd0: ctrl_reg <= wdata;
          2'd1: load_reg <= wdata;
          2'd3: if (wdata[0]) status_reg[0] <= 0; // W1C: write 1 to clear
        endcase
        bvalid <= 1;
      end else if (bvalid && bready) bvalid <= 0;
    end
  end

  // AXI Read
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin arready<=0; rvalid<=0; rdata<=0; end
    else begin
      arready <= arvalid;
      if (arvalid) begin
        rvalid <= 1;
        case (araddr[3:2])
          2'd0: rdata <= ctrl_reg;
          2'd1: rdata <= load_reg;
          2'd2: rdata <= count_reg;
          2'd3: rdata <= status_reg;
        endcase
      end else if (rvalid && rready) rvalid <= 0;
    end
  end

  // Timer logic
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      count_reg  <= 0;
      status_reg <= 0;
      irq        <= 0;
    end else begin
      irq <= 0; // default
      if (enable) begin
        if (count_reg == 0) begin
          irq            <= 1;
          status_reg[0]  <= 1;
          if (auto_reload) count_reg <= load_reg;
          else             ctrl_reg[0] <= 0; // disable
        end else
          count_reg <= count_reg - 1;
      end else
        count_reg <= load_reg; // preload when disabled
    end
  end
endmodule

module tb_zynq_timer;
  logic clk=0, rst_n;
  logic [3:0]  awaddr, araddr;
  logic        awvalid, wvalid, arvalid, bready, rready;
  logic [31:0] wdata, rdata;
  logic        awready, wready, bvalid, arready, rvalid;
  logic [1:0]  bresp, rresp;
  logic        irq;

  zynq_timer dut(.*);
  always #5 clk = ~clk;

  task write_reg(input [3:0] addr, input [31:0] data);
    awaddr=addr; wdata=data; awvalid=1; wvalid=1; bready=1;
    @(posedge clk); awvalid=0; wvalid=0;
    wait(bvalid); @(posedge clk);
  endtask

  task read_reg(input [3:0] addr, output [31:0] data);
    araddr=addr; arvalid=1; rready=1;
    @(posedge clk); arvalid=0;
    wait(rvalid); data=rdata; @(posedge clk);
  endtask

  initial begin
    rst_n=0; awvalid=0; wvalid=0; arvalid=0; bready=0; rready=0;
    repeat(2) @(posedge clk); rst_n=1;

    // Set LOAD = 10
    write_reg(4'h4, 32'd10);
    // Enable timer (bit0=1, bit1=0 no auto-reload)
    write_reg(4'h0, 32'h1);

    // Wait for IRQ
    wait(irq==1);
    $display("IRQ received!");

    // Read STATUS — should be 1
    logic [31:0] status;
    read_reg(4'hC, status);
    assert(status[0]==1) else $error("STATUS not set");

    // Clear STATUS (write 1 to bit0)
    write_reg(4'hC, 32'h1);
    read_reg(4'hC, status);
    assert(status[0]==0) else $error("STATUS not cleared");

    $display("Zynq Timer PASSED");
    $finish;
  end
endmodule

