// 1080p60 Video Pipeline
// Pixel format: RGB888 (24-bit per pixel)
// Clock: 148.5MHz → 1 pixel per clock

// Stage 1: Grayscale conversion
// Gray = 0.299R + 0.587G + 0.114B
// Fixed point: Gray = (77R + 150G + 29B) >> 8
module rgb_to_gray (
  input  logic        clk,
  input  logic        valid, hsync, vsync,
  input  logic [7:0]  r, g, b,
  output logic        valid_out, hs_out, vs_out,
  output logic [7:0]  gray
);
  logic [15:0] sum;
  logic valid_r, hs_r, vs_r;

  always_ff @(posedge clk) begin
    // Multiply coefficients (DSP48 inferred)
    sum      <= 8'd77*r + 8'd150*g + 8'd29*b;
    valid_r  <= valid;
    hs_r     <= hsync;
    vs_r     <= vsync;
    // Divide by 256 (right shift 8)
    gray     <= sum[15:8];
    valid_out <= valid_r;
    hs_out    <= hs_r;
    vs_out    <= vs_r;
  end
endmodule
// 2-cycle latency
// Uses 3 DSP48 multipliers (one per coefficient)
// Processes 148.5 million pixels per second

