// Lab 10: Video Pixel Pipeline
module video_pipeline (
  input  logic        clk, rst_n,
  input  logic        valid_in, hsync_in, vsync_in,
  input  logic [7:0]  r, g, b,
  input  logic [7:0]  threshold,
  output logic        valid_out, hsync_out, vsync_out,
  output logic [7:0]  pixel_out
);
  // Stage 1a: multiply (cycle 1)
  logic [15:0] r_mult, g_mult, b_mult;
  logic valid_1a, hs_1a, vs_1a;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin valid_1a<=0; end
    else begin
      r_mult   <= 8'd77  * r;
      g_mult   <= 8'd150 * g;
      b_mult   <= 8'd29  * b;
      valid_1a <= valid_in;
      hs_1a    <= hsync_in;
      vs_1a    <= vsync_in;
    end
  end

  // Stage 1b: sum and shift (cycle 2)
  logic [7:0] gray;
  logic valid_1b, hs_1b, vs_1b;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin valid_1b<=0; end
    else begin
      gray     <= (r_mult + g_mult + b_mult) >> 8;
      valid_1b <= valid_1a;
      hs_1b    <= hs_1a;
      vs_1b    <= vs_1a;
    end
  end

  // Stage 2: threshold (cycle 3)
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin valid_out<=0; end
    else begin
      pixel_out  <= (gray > threshold) ? 8'hFF : 8'h00;
      valid_out  <= valid_1b;
      hsync_out  <= hs_1b;
      vsync_out  <= vs_1b;
    end
  end
endmodule

module tb_video;
  logic clk=0, rst_n;
  logic valid_in, hsync_in=0, vsync_in=0;
  logic valid_out, hsync_out, vsync_out;
  logic [7:0] r,g,b, threshold, pixel_out;

  video_pipeline dut(.*);
  always #5 clk = ~clk;

  // Capture output pixels
  logic [7:0] out_pixels [5];
  int out_count=0;
  always @(posedge clk)
    if (valid_out) begin
      out_pixels[out_count] = pixel_out;
      out_count++;
    end

  initial begin
    rst_n=0; valid_in=0; threshold=8'd128;
    r=0; g=0; b=0;
    repeat(2) @(posedge clk); rst_n=1;

    // Send 5 pixels
    // Pixel 1: R=255,G=0,B=0 → gray=77 → below 128 → BLACK
    // Pixel 2: R=255,G=255,B=255 → gray=256>>8=255 → above 128 → WHITE
    // Pixel 3: R=0,G=255,B=0 → gray=150 → above 128 → WHITE
    // Pixel 4: R=0,G=0,B=255 → gray=29 → below 128 → BLACK
    // Pixel 5: R=128,G=128,B=128 → gray=128 → NOT above → BLACK

    logic [7:0] test_r[5] = '{255,255,0,0,128};
    logic [7:0] test_g[5] = '{0,255,255,0,128};
    logic [7:0] test_b[5] = '{0,255,0,255,128};

    for (int i=0; i<5; i++) begin
      r=test_r[i]; g=test_g[i]; b=test_b[i];
      valid_in=1; @(posedge clk); #1;
    end
    valid_in=0;

    // Wait for pipeline (3 cycles latency)
    repeat(5) @(posedge clk);

    // Verify: BLACK, WHITE, WHITE, BLACK, BLACK
    assert(out_pixels[0]==8'h00) else $error("Pixel0 FAIL");
    assert(out_pixels[1]==8'hFF) else $error("Pixel1 FAIL");
    assert(out_pixels[2]==8'hFF) else $error("Pixel2 FAIL");
    assert(out_pixels[3]==8'h00) else $error("Pixel3 FAIL");
    assert(out_pixels[4]==8'h00) else $error("Pixel4 FAIL");

    $display("Video pipeline PASSED");
    $finish;
  end
endmodule

