// INTERVIEW REFERENCE: Edge Detector
module edge_detect (
  input  logic clk, rst_n, sig,
  output logic rising, falling, any_edge
);
  logic sig_d;
  always_ff @(posedge clk or negedge rst_n)
    if (!rst_n) sig_d <= 0;
    else        sig_d <= sig;

  assign rising  = sig & ~sig_d;   // was 0, now 1
  assign falling = ~sig & sig_d;   // was 1, now 0
  assign any_edge = rising | falling;
endmodule

// INTERVIEW REFERENCE: PWM Generator
module pwm_gen #(parameter WIDTH=8) (
  input  logic             clk, rst_n,
  input  logic [WIDTH-1:0] duty,   // 0-255
  output logic             pwm_out
);
  logic [WIDTH-1:0] cnt;
  always_ff @(posedge clk or negedge rst_n)
    if (!rst_n) cnt <= 0;
    else        cnt <= cnt + 1;    // free-running counter
  assign pwm_out = (cnt < duty);   // high when cnt < duty
endmodule

// INTERVIEW REFERENCE: Button Debouncer
module debounce #(parameter N=20) (
  input  logic clk, rst_n, btn_raw,
  output logic btn_clean
);
  logic [N-1:0] shift;
  always_ff @(posedge clk or negedge rst_n)
    if (!rst_n) shift <= 0;
    else        shift <= {shift[N-2:0], btn_raw};
  assign btn_clean = &shift; // all 1s = stable high
endmodule

// FPGA vs ASIC:
// FPGA: prototyping, low volume (<10K), needs field updates
// ASIC: high volume (>100K), max performance, minimum power
// FPGA is 10-100x larger die, 5-10x slower Fmax, 10x higher $/unit

// DSP48 is inferred by:
// a*b              → multiply
// a*b+c            → multiply-add
// p <= p + (a*b)   → accumulate
// a[n]*h[n] loops  → FIR filter

// CDC safe methods:
// 1-bit: 2-FF synchronizer
// N-bit counter: Gray code + 2-FF
// N-bit data: async FIFO
// Pulse: toggle synchronizer

// Fix WNS=-3ns:
// Option 1: add pipeline register (most reliable)
// Option 2: reduce logic between FFs (simplify combo)
// Option 3: phys_opt_design -directive AggressiveExplore
// Option 4: relax clock if possible
// Option 5: place cells closer with Pblock

// 4-bit Gray code counter:
module gray_counter (
  input  logic       clk, rst_n,
  output logic [3:0] gray_out
);
  logic [3:0] bin;
  always_ff @(posedge clk or negedge rst_n)
    if (!rst_n) bin <= 0;
    else        bin <= bin + 1;
  assign gray_out = bin ^ (bin >> 1);
endmodule

