// Lab 11: Classic Synchronous FIFO
module sync_fifo #(
  parameter DATA_W = 8,
  parameter DEPTH  = 16
) (
  input  logic              clk, rst_n,
  input  logic              wr_en, rd_en,
  input  logic [DATA_W-1:0] wr_data,
  output logic [DATA_W-1:0] rd_data,
  output logic              full, empty,
  output logic [$clog2(DEPTH):0] count
);
  localparam AW = $clog2(DEPTH);

  logic [DATA_W-1:0] mem [DEPTH];
  logic [AW-1:0]     wr_ptr, rd_ptr;

  // Write logic
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) wr_ptr <= 0;
    else if (wr_en && !full) begin
      mem[wr_ptr] <= wr_data;
      wr_ptr <= wr_ptr + 1;
    end
  end

  // Read logic (synchronous — 1 cycle latency)
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) rd_ptr <= 0;
    else if (rd_en && !empty) begin
      rd_data <= mem[rd_ptr];
      rd_ptr  <= rd_ptr + 1;
    end
  end

  // Count logic
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) count <= 0;
    else begin
      case ({wr_en && !full, rd_en && !empty})
        2'b10: count <= count + 1;  // write only
        2'b01: count <= count - 1;  // read only
        default: ;                   // both or neither
      endcase
    end
  end

  assign full  = (count == DEPTH);
  assign empty = (count == 0);
endmodule

module tb_fifo_interview;
  logic clk=0, rst_n;
  logic wr_en, rd_en;
  logic [7:0] wr_data, rd_data;
  logic full, empty;
  logic [4:0] count;  // $clog2(16)+1 = 5 bits

  sync_fifo #(.DATA_W(8),.DEPTH(16)) dut(.*);
  always #5 clk = ~clk;

  initial begin
    rst_n=0; wr_en=0; rd_en=0; wr_data=0;
    @(posedge clk); rst_n=1;

    // Test 1: Fill FIFO
    wr_en=1;
    for (int i=0; i<16; i++) begin
      wr_data=i; @(posedge clk);
    end
    wr_en=0; @(posedge clk); #1;
    assert(full==1)  else $error("Should be full");
    assert(count==16) else $error("Count=%0d",count);
    $display("FIFO full test PASSED");

    // Test 2: Empty FIFO
    rd_en=1;
    repeat(16) @(posedge clk);
    rd_en=0; @(posedge clk); #1;
    assert(empty==1) else $error("Should be empty");
    $display("FIFO empty test PASSED");

    // Test 3: Simultaneous R+W
    wr_data=8'hAA; wr_en=1;
    @(posedge clk); wr_en=0;
    wr_data=8'hBB; wr_en=1; rd_en=1;
    @(posedge clk); #1;
    $display("Simultaneous R+W: count=%0d", count);
    wr_en=0; rd_en=0;

    $display("** FIFO Interview PASSED **");
    $finish;
  end
endmodule

// Lab 12: FINAL BOSS — Complete FIR Accelerator

// Coefficient BRAM (8x8)
module coeff_bram (
  input  logic       clk,
  input  logic       we,
  input  logic [2:0] waddr, raddr,
  input  logic [7:0] wdata,
  output logic [7:0] rdata
);
  logic [7:0] mem [8];
  // Initialize with default coefficients
  initial begin
    mem[0]=1; mem[1]=2; mem[2]=3; mem[3]=4;
    mem[4]=4; mem[5]=3; mem[6]=2; mem[7]=1;
  end
  always_ff @(posedge clk) if (we) mem[waddr] <= wdata;
  always_ff @(posedge clk) rdata <= mem[raddr];
endmodule

// 8-tap FIR Filter core
module fir8 (
  input  logic        clk, rst_n,
  input  logic        enable,
  input  logic        s_tvalid,
  input  logic signed [7:0]  s_tdata,
  output logic        m_tvalid,
  output logic signed [15:0] m_tdata,
  // Coefficient interface
  output logic [2:0]  coeff_addr,
  input  logic signed [7:0]  coeff_data
);
  logic signed [7:0]  delay [8];
  logic signed [15:0] products [8];
  logic signed [17:0] acc;
  logic [2:0]  tap_idx;
  logic valid_d1, valid_d2;

  // Delay line
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) foreach(delay[i]) delay[i]<=0;
    else if (s_tvalid && enable) begin
      delay[0] <= s_tdata;
      for (int i=1; i<8; i++) delay[i] <= delay[i-1];
    end
  end

  // Parallel multiply (all 8 taps)
  // Simplified: use combinational multiply then register
  logic [2:0] rd_addr;
  // In real design: preload coefficients from BRAM
  // Here: use sequential tap loading for simplicity
  logic signed [7:0] coeffs [8];
  initial begin
    coeffs[0]=1; coeffs[1]=2; coeffs[2]=3; coeffs[3]=4;
    coeffs[4]=4; coeffs[5]=3; coeffs[6]=2; coeffs[7]=1;
  end

  // Pipeline stage 1: all multiplications
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      foreach(products[i]) products[i]<=0;
      valid_d1<=0;
    end else begin
      valid_d1 <= s_tvalid && enable;
      for (int i=0; i<8; i++)
        products[i] <= coeffs[i] * delay[i];
    end
  end

  // Pipeline stage 2: accumulate
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin m_tdata<=0; m_tvalid<=0; end
    else begin
      m_tvalid <= valid_d1;
      acc = 0;
      for (int i=0; i<8; i++) acc += products[i];
      m_tdata <= acc[15:0];
    end
  end

  assign s_tready  = enable;
  assign coeff_addr = 0; // placeholder
endmodule

// Top-level accelerator
module fir_accelerator (
  input  logic        clk, rst_n,
  // AXI-Lite (simplified)
  input  logic [3:0]  s_awaddr, s_araddr,
  input  logic        s_awvalid, s_wvalid, s_arvalid,
  input  logic        s_bready, s_rready,
  input  logic [31:0] s_wdata,
  output logic        s_awready, s_wready, s_bvalid,
  output logic        s_arready, s_rvalid,
  output logic [31:0] s_rdata,
  output logic [1:0]  s_bresp, s_rresp,
  // AXI-Stream
  input  logic        s_tvalid,
  input  logic signed [7:0] s_tdata,
  output logic        s_tready,
  output logic        m_tvalid,
  output logic signed [15:0] m_tdata
);
  assign s_bresp=0; assign s_rresp=0;

  // Registers
  logic [31:0] ctrl_reg;  // [0]=enable
  logic [31:0] coeff_addr_reg, coeff_data_reg;

  // AXI write
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin ctrl_reg<=0; s_awready<=0; s_wready<=0; s_bvalid<=0; end
    else begin
      s_awready <= s_awvalid;
      s_wready  <= s_wvalid;
      if (s_awvalid && s_wvalid) begin
        case (s_awaddr[3:2])
          2'd0: ctrl_reg       <= s_wdata;
          2'd2: coeff_addr_reg <= s_wdata;
          2'd3: coeff_data_reg <= s_wdata;
        endcase
        s_bvalid <= 1;
      end else if (s_bvalid && s_bready) s_bvalid <= 0;
    end
  end

  // AXI read
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin s_arready<=0; s_rvalid<=0; s_rdata<=0; end
    else begin
      s_arready <= s_arvalid;
      if (s_arvalid) begin
        s_rvalid <= 1;
        case (s_araddr[3:2])
          2'd0: s_rdata <= ctrl_reg;
          2'd1: s_rdata <= {31'b0, m_tvalid}; // status
        endcase
      end else if (s_rvalid && s_rready) s_rvalid <= 0;
    end
  end

  // FIR core
  logic [2:0] coeff_addr;
  logic [7:0] coeff_data;

  fir8 fir (
    .clk,.rst_n,.enable(ctrl_reg[0]),
    .s_tvalid,.s_tdata,.m_tvalid,.m_tdata,
    .coeff_addr,.coeff_data
  );

  assign s_tready = ctrl_reg[0];
endmodule

// FINAL BOSS TESTBENCH
module tb_fir_final;
  logic clk=0, rst_n;
  logic [3:0]  s_awaddr, s_araddr;
  logic        s_awvalid, s_wvalid, s_arvalid, s_bready, s_rready;
  logic [31:0] s_wdata, s_rdata;
  logic        s_awready, s_wready, s_bvalid, s_arready, s_rvalid;
  logic [1:0]  s_bresp, s_rresp;
  logic        s_tvalid, s_tready, m_tvalid;
  logic signed [7:0]  s_tdata;
  logic signed [15:0] m_tdata;

  fir_accelerator dut(.*);
  always #5 clk = ~clk;

  // Capture outputs
  logic signed [15:0] outputs [20];
  int out_count=0;
  always @(posedge clk)
    if (m_tvalid) begin outputs[out_count]=m_tdata; out_count++; end

  task axi_write(input [3:0] addr, input [31:0] data);
    s_awaddr=addr; s_wdata=data; s_awvalid=1; s_wvalid=1; s_bready=1;
    @(posedge clk); s_awvalid=0; s_wvalid=0;
    wait(s_bvalid); @(posedge clk);
  endtask

  initial begin
    rst_n=0; s_awvalid=0; s_wvalid=0; s_arvalid=0;
    s_bready=0; s_rready=0; s_tvalid=0; s_tdata=0;
    repeat(2) @(posedge clk); rst_n=1;

    // Enable accelerator
    axi_write(4'h0, 32'h1);

    // Stream 12 samples [1..8, 0,0,0,0]
    $display("=== FINAL BOSS: FIR Accelerator ===");
    s_tvalid=1;
    for (int i=1; i<=8; i++) begin
      s_tdata=i; @(posedge clk);
    end
    repeat(4) begin s_tdata=0; @(posedge clk); end
    s_tvalid=0;

    // Wait for outputs
    repeat(6) @(posedge clk); #1;

    $display("Output count: %0d", out_count);
    $display("First output: %0d", outputs[0]);
    $display("Outputs: %0d %0d %0d %0d",
             outputs[0],outputs[1],outputs[2],outputs[3]);

    // Verify outputs are non-zero (FIR is working)
    assert(out_count > 0) else $error("No outputs produced!");
    assert(outputs[0] != 0) else $error("Zero output — FIR not working");

    $display("=== FINAL BOSS PASSED ===");
    $finish;
  end
endmodule
